def _serialize_class_weights(obj):
    if obj is None:
        return None
    try:
        import numpy as np
        if isinstance(obj, torch.Tensor):
            return obj.detach().cpu().numpy().tolist()
        elif isinstance(obj, np.ndarray):
            return obj.tolist()
        elif isinstance(obj, (list, tuple)):
            return list(obj)
        else:
            return None
    except Exception:
        return None

